1	type Cells = number[][];
2	
3	const countNeighbors = (cells: Cells, x: number, y: number): number => {
4	  return cells.filter(([cx, cy]) =>
5	    Math.abs(cx - x) <= 1 && Math.abs(cy - y) <= 1 && !(cx === x && cy === y)
6	  ).length;
7	};
8	
9	export function nextGeneration(cells: Cells): Cells {
10	  return cells.filter(([x, y]) => {
11	    const neighborCount = countNeighbors(cells, x, y);
12	    return neighborCount === 2 || neighborCount === 3;
13	  });
14	}
